{"code": "import json

# Load all articles
articles_file = locals()['var_functions.query_db:28']
if isinstance(articles_file, str):
    with open(articles_file, 'r') as f:
        articles = json.load(f)
else:
    articles = articles_file

# Define sports keywords
sports_keywords = [
    'sports', 'sport', 'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf',
    'athlete', 'athletic', 'game', 'tournament', 'olympic', 'olympics', 'league', 
    'team', 'win', 'champion', 'championship', 'match', 'cup', 'playoff', 'playoffs',
    'nfl', 'nba', 'mlb', 'nhl', 'world cup', 'premier league', 'racing', 'race',
    'medal', 'gold medal', 'silver medal', 'bronze medal', 'coach', 'player',
    'season', 'score', 'victory', 'defeat', 'competition', 'compete', 'competing'
]

# Find sports articles
sports_articles = []
for article in articles:
    title = article.get('title', '').lower()
    description = article.get('description', '').lower()

    # Check if it's a sports article
    is_sports = False
    for keyword in sports_keywords:
        if keyword in title or keyword in description:
            is_sports = True
            break

    if is_sports:
        sports_articles.append({
            'title': article['title'],
            'description': article['description'],
            'desc_length': len(article.get('description', ''))
        })

# Sort by description length and get the longest one
if sports_articles:
    sports_articles.sort(key=lambda x: x['desc_length'], reverse=True)
    longest_article = sports_articles[0]
    result = {
        'title': longest_article['title'],
        'description_length': longest_article['desc_length'],
        'total_sports_articles': len(sports_articles)
    }
else:
    result = {'error': 'No sports articles found'}

print('__RESULT__:')
print(json.dumps(result))"}

